import { AppState } from '../store/state'
import { ITEMS, CATEGORIES } from '../data/checklist'

const BUCKET_IMG = 'data:image/png;base64,'

const FLOATERS = [
  { label:'🦘 캥거루',     top:'6%',  left:'4%',   anim:'floatA', delay:0    },
  { label:'🏖 골드코스트', top:'9%',  right:'4%',  anim:'floatB', delay:0.9  },
  { label:'🌊 본다이비치', top:'52%', left:'2%',   anim:'floatB', delay:0.7  },
  { label:'🪃 부메랑',     top:'57%', right:'3%',  anim:'floatA', delay:1.1  },
  { label:'🐨 코알라',     top:'72%', left:'5%',   anim:'floatB', delay:0.5  },
  { label:'🐊 케언즈',     top:'67%', right:'5%',  anim:'floatA', delay:0.3  },
  { label:'🌿 멜버른',     top:'30%', left:'2%',   anim:'floatA', delay:0.8  },
  { label:'✈️ 시드니',     top:'25%', right:'3%',  anim:'floatB', delay:1.4  },
]

const PREVIEW_DEFAULTS = [
  { label:'치과 (스케일링/충치)', emoji:'🦷' },
  { label:'올리브영',             emoji:'🛍' },
]

type Props = { state: AppState; onStart: () => void }

export default function LandingPage({ state, onStart }: Props) {
  const done  = Object.keys(state.selected).length
  const total = ITEMS.length + state.customItems.length

  const checkedItems = ITEMS.filter(i => state.selected[i.id]).slice(0, 3)
    .map(i => ({ label: i.label, emoji: i.emoji }))
  const previewItems = checkedItems.length > 0 ? checkedItems : PREVIEW_DEFAULTS

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(170deg, #eef2fa 0%, #f3f6fb 50%, #f5f7fb 100%)',
      position: 'relative',
      overflow: 'hidden',
      display: 'flex',
      flexDirection: 'column',
      alignItems: 'center',
      fontFamily: '-apple-system,"Apple SD Gothic Neo","Noto Sans KR",sans-serif',
    }}>

      {/* 떠다니는 말풍선 */}
      {FLOATERS.map((f, i) => (
        <div key={i} style={{
          position: 'absolute',
          top: f.top,
          left: (f as any).left,
          right: (f as any).right,
          background: 'rgba(210,224,248,0.75)',
          backdropFilter: 'blur(8px)',
          borderRadius: 40,
          padding: '6px 13px',
          fontSize: 12,
          fontWeight: 700,
          color: '#4A6FA5',
          whiteSpace: 'nowrap',
          boxShadow: '0 1px 8px rgba(100,130,200,0.10)',
          animation: `${f.anim} 2.8s ease-in-out ${f.delay}s infinite`,
          zIndex: 1,
          pointerEvents: 'none',
        } as React.CSSProperties}>{f.label}</div>
      ))}

      {/* 메인 콘텐츠 */}
      <div style={{
        zIndex: 2,
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        marginTop: '30%',
        width: '100%',
        paddingBottom: 110,
        textAlign: 'center',
      }}>

        {/* 중앙 뱃지 */}
        <div style={{
          background: 'rgba(200,218,248,0.88)',
          backdropFilter: 'blur(8px)',
          borderRadius: 40,
          padding: '7px 16px',
          fontSize: 12, fontWeight: 700, color: '#3a5fa5',
          marginBottom: 16,
          animation: 'floatB 3.2s ease-in-out 0.4s infinite',
          boxShadow: '0 1px 8px rgba(100,130,200,0.10)',
        }}>✈️ 호주 여행 버킷리스트</div>

        {/* 호주가자 shimmer */}
        <h1 style={{
          fontSize: 48,
          fontWeight: 900,
          letterSpacing: -2,
          margin: '0 0 6px',
          background: 'linear-gradient(90deg, #1E4D83 0%, #1E4D83 15%, #5B9BD5 35%, #A8C8F0 50%, #5B9BD5 65%, #1E4D83 85%, #1E4D83 100%)',
          backgroundSize: '300% auto',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          backgroundClip: 'text',
          animation: 'shimmer 3s linear infinite',
        }}>호주가자</h1>

        <p style={{ color: '#7a8fb5', fontSize: 13, fontWeight: 700, marginBottom: 16, lineHeight: 1.7 }}>
          호주에서 꼭 해야 할 것들,<br/>기록하자
        </p>

        {/* 버킷 이미지 */}
        <div style={{ width: '55%', maxWidth: 200, marginBottom: 16 }}>
          <img
            src={BUCKET_IMG}
            alt="버킷"
            style={{
              width: '100%', height: 'auto', objectFit: 'contain', display: 'block',
              animation: 'floatA 3.5s ease-in-out infinite',
            }}
          />
        </div>

        {/* 카테고리 칩 */}
        <div style={{
          display: 'flex', gap: 6, flexWrap: 'wrap', justifyContent: 'center',
          padding: '0 20px', marginBottom: 18,
        }}>
          {CATEGORIES.map(cat => (
            <div key={cat.id} style={{
              background: 'rgba(255,255,255,0.85)',
              border: '1px solid rgba(30,77,131,0.12)',
              borderRadius: 99, padding: '5px 12px',
              fontSize: 11, fontWeight: 700, color: '#4A6FA5',
              boxShadow: '0 1px 4px rgba(100,130,200,0.08)',
            }}>{cat.label}</div>
          ))}
        </div>

        {/* 미니 버킷리스트 카드 */}
        <div style={{
          width: 'calc(100% - 48px)',
          maxWidth: 300,
          background: 'rgba(255,255,255,0.92)',
          borderRadius: 16,
          padding: '14px 16px 12px',
          boxShadow: '0 4px 24px rgba(100,130,200,0.12)',
          border: '1px solid rgba(30,77,131,0.07)',
          textAlign: 'left',
        }}>
          <div style={{ color: '#1E4D83', fontWeight: 900, fontSize: 11, letterSpacing: 1.5, marginBottom: 10, textAlign: 'center' }}>
            호주가자 버킷리스트
          </div>
          <div style={{ borderTop: '1px dashed rgba(30,77,131,0.15)', marginBottom: 8 }}/>
          {previewItems.map((item, i) => (
            <div key={i} style={{
              display: 'flex', justifyContent: 'space-between', alignItems: 'center',
              fontSize: 12, color: '#3A4A5C', padding: '4px 0',
              borderBottom: '1px solid rgba(30,77,131,0.05)',
            }}>
              <span style={{ fontWeight: 500 }}>{item.emoji} {item.label}</span>
              <span style={{ color: '#1E4D83', fontWeight: 800, fontSize: 11 }}>✓</span>
            </div>
          ))}
          {/* 흐릿한 빈 줄 2개 */}
          {[0,1].map(i => (
            <div key={i} style={{ height: 11, background: '#EEF2FA', borderRadius: 4, margin: '6px 0' }}/>
          ))}
          <div style={{ borderTop: '1px dashed rgba(30,77,131,0.15)', margin: '8px 0 4px' }}/>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <span style={{ fontWeight: 900, fontSize: 12, color: '#0F1B2D' }}>TOTAL</span>
            <span style={{ color: done > 0 ? '#1E4D83' : '#bbb', fontWeight: 900, fontSize: 12 }}>
              {done > 0 ? `${done}/${total}건` : `??/${total}건`}
            </span>
          </div>
        </div>
      </div>

      {/* CTA 버튼 */}
      <div style={{
        position: 'fixed', bottom: 0,
        left: '50%', transform: 'translateX(-50%)',
        width: '100%', maxWidth: 390,
        padding: '10px 16px 28px',
        background: 'linear-gradient(to top, #eef2fa 60%, transparent)',
        zIndex: 20,
        boxSizing: 'border-box',
      }}>
        <button onClick={onStart} style={{
          width: '100%', height: 52,
          background: 'linear-gradient(160deg, #3A7FCC, #1E4D83)',
          color: '#fff', border: 'none', borderRadius: 14,
          fontSize: 15, fontWeight: 900, cursor: 'pointer',
          letterSpacing: 0.3,
          boxShadow: '0 4px 16px rgba(30,77,131,0.28)',
        }}>출발하기 →</button>
        <p style={{ textAlign: 'center', fontSize: 11, color: '#8AAAC8', marginTop: 7, fontWeight: 700 }}>
          호주에서 꼭 해야 할 것들을 정리해보세요
        </p>
      </div>
    </div>
  )
}
